INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-07100', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '如果你想引用古代的名言佳句，期勉自己要有「鍥而不捨，不辭艱難」的精神，下列何者最為適合？', '["如切如磋，如琢如磨（《詩經．衛風．淇奧》）", "揀盡寒枝不肯棲，寂寞沙洲冷（蘇軾〈卜算子〉）", "路漫漫其修遠兮，吾將上下而求索（屈原〈離騷〉）", "戰戰兢兢，如臨深淵，如履薄冰（《詩經．小雅．小旻》）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "8024526b992d", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07101', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列關於先秦諸子的敘述，正確的選項是：', '["墨子：提倡節約，反對奢侈，反對音樂，反對宿命論，認為天沒有意志，是自然天", "莊子：道家代表人物，認為自然、無為、逍遙是道的基本要求，是人生的基本方向", "荀子：儒家代表人物，思想核心為仁、義，將孔子的德治發展成為仁政，提倡禮法兼治", "韓非子：法家代表人物，於政治上主張只要國君遵行法理，不須依賴術、勢，便能安定國家"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "8024526b992d", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07102', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「對酒當歌，人生幾何？譬如朝露，去日苦多。慨當以慷，憂思難忘；何以解憂，唯有杜康。青青子衿， 悠悠我心；但為君故，沉吟至今。呦呦鹿鳴，食野之苹。我有嘉賓，鼓瑟吹笙。明明如月，何時可掇？ 憂從中來，不可斷絕。越陌度阡，枉用相存，契闊談讌，心念舊恩。月明星稀，烏鵲南飛，繞樹三匝， 何枝可依？山不厭高，海不厭深，周公吐哺，天下歸心。」（曹操〈短歌行〉） 此詩藉助生動的比喻，把抽象的概念化為具體可感的形象，淋漓抒發求賢不得的苦悶和思賢若渴的情意。 以下那個選項敘述錯誤？', '["以「朝露」的轉瞬即逝，比喻人生短促，凸顯求賢的緊迫感", "以「一沐三握髮，一飯三吐哺」的周公自比，表示對天下賢士的熱誠歡迎", "用「明明如月，何時可掇？憂從中來，不可斷絕」，抒發賢士有志難伸、懷才不遇的感傷", "透過「我有嘉賓，鼓瑟吹笙」和「契闊談讌，心念舊恩」之宴請賓客，表現禮賢下士、慕悅賢才的心意"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "8024526b992d", "answer_pdf_sha1": "e5c67479d01d", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07103', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列與親屬有關的詞語，解釋正確的是：', '["妯娌：兄弟的妻子彼此互相稱呼", "連襟：男子結拜成兄弟之稱呼", "外甥：稱自己兄弟的兒子", "翁姑：指女子丈夫的姐妹"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "3e5c64ad959d", "answer_pdf_sha1": "b5544dd25c61", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07104', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列書信提稱語的用法，正確的是：', '["「硯席、硯右」對象是晚輩", "「函丈、壇席」對象是學生", "「尊鑒、鈞鑒」對象是長官", "「台鑒、惠鑒」對象是老師"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "3e5c64ad959d", "answer_pdf_sha1": "b5544dd25c61", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07105', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列先秦諸子的思想，正確的是：', '["上善若水，水善利萬物而不爭。夫唯不爭，故無尤‥‥‥人法地，地法天，天法 道，道法自然—莊子", "天下莫大於秋毫之末，而大山為小；莫壽乎殤子，而彭祖為夭。天地與我並存， 而萬物與我為一—老子", "人生而有欲，欲而不得，則不能無求，求而無度量分界，則不能不爭‥‥‥先王 惡其亂也，故制禮以分之—荀子", "國家昏亂，則語之尚賢、尚同；國家貧，則語之節用、節葬‥‥‥國家務奪侵凌， 則語之兼愛、非攻—管子"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "3e5c64ad959d", "answer_pdf_sha1": "b5544dd25c61", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07106', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列所述人物典故，正確的選項是：', '["你原本是一朵好看的青蓮，腳在泥中，頭頂藍天，無需潁川之水，一身紅塵已被 酒精洗淨—周敦頤", "剛直不阿，留得正氣沖霄漢；幽愁發憤，著成信史照塵寰—司馬遷", "他嚮往變動，也不過是為了拯救愛新覺羅王朝的衰亡，可是也會落得泣血瀛臺， 身死神傷。這幽幽小島，淒淒小洲，竟成了他岑寂的囚牢—康有為", "中秋豈可無月，無月教我如何想像你早年的容顏，教我如何能感應，一夜的鄉心， 五處的悸動—李白"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "3e5c64ad959d", "answer_pdf_sha1": "b5544dd25c61", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07107', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '①《四書》是指《論語》、《孟子》、《大學》、《中庸》  ②《論語》是孔子弟', '["《四書》是由北宋程顥所編定", "《大學》所謂「三綱 領」，是指「君臣、父子、夫婦」  ⑤《四書》中的《大學》、《中庸》，原是 《禮記》中的篇章。以上對《四書》的說明，正確的是：", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "3e5c64ad959d", "answer_pdf_sha1": "b5544dd25c61", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07108', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '在文句中，兩兩相對，字數相等、句法相似、詞性相同、意義相關的修辭技巧，叫', '["南北百里，東西一舍", "牛驥同 一皁，雞棲鳳凰食", "悟已往之不諫，知來者之可追", "日出而林霏開，雲歸而巖 穴暝"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "3e5c64ad959d", "answer_pdf_sha1": "b5544dd25c61", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07109', 'social-worker', 'social-worker-moex-101-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '孟子曰：「原泉混混，盈科而後進。」下列那一句的意思，與此最相近？①泰山不', '["水往低處流，人往高處爬", "循序漸進，方能學有所成", "天行健，君子以自強不息", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "3e5c64ad959d", "answer_pdf_sha1": "b5544dd25c61", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0902", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
